import{_ as i,o as t,c as l,a6 as s,ge as o,gf as e,fI as n,fN as p,fk as g,fi as h,fn as c,gg as d,gh as r,eD as m,gi as b,gj as u,gk as _,gl as f,gm as k}from"./chunks/framework.UYVGz2W_.js";const v=JSON.parse('{"title":"よくある質問","description":"","frontmatter":{},"headers":[],"relativePath":"ja/faq/index.md","filePath":"ja/faq/index.md"}'),P={name:"ja/faq/index.md"};function x(T,a,y,K,S,A){return t(),l("div",null,[...a[0]||(a[0]=[s('<h1 id="よくある質問" tabindex="-1">よくある質問 <a class="header-anchor" href="#よくある質問" aria-label="Permalink to “よくある質問”">​</a></h1><p>このFAQガイドでは、Kitsuの一般的な問題に対する簡単な解決策を提供します。ログインの問題、タスク管理、生産の整理など、以下のセクションでステップバイステップの説明と役立つヒントを見つけることができます。さらにサポートが必要な場合は、詳細な<a href="./../configure-kitsu/">Kitsuのドキュメント</a>を確認するか、サポートにお問い合わせください。</p><hr><h2 id="ログインの問題" tabindex="-1">ログインの問題 <a class="header-anchor" href="#ログインの問題" aria-label="Permalink to “ログインの問題”">​</a></h2><h3 id="kitsuにログインできません" tabindex="-1">Kitsuにログインできません <a class="header-anchor" href="#kitsuにログインできません" aria-label="Permalink to “Kitsuにログインできません”">​</a></h3><p>まず、使用している<strong>ウェブアドレス</strong>を確認してください。</p><ul><li><p>ウェブアドレスが <strong>account.cg-wire.com/signin</strong> でCGWireのロゴが表示されている場合は、<strong>間違ったページ</strong>にアクセスしています。</p><p><img src="'+o+'" alt="Account login"></p><p><strong>アカウントページ</strong>は、購読や請求書の管理専用です。購読を登録していない限り、アクセスできません。</p></li><li><p>Kitsuインスタンスの正しいウェブアドレスは、<strong>your-studio-name.cg-wire.com</strong> の形式である必要があります。このページでは、Kitsuのロゴとログイン画面が表示されます。</p><p><img src="'+e+'" alt="Kitsu login"></p></li></ul><p>正しいリンクがわからない場合は：</p><ul><li>受信した招待メールを確認してください。</li><li>スタジオの管理者にお問い合わせください。</li></ul><hr><h2 id="タスク管理" tabindex="-1">タスク管理 <a class="header-anchor" href="#タスク管理" aria-label="Permalink to “タスク管理”">​</a></h2><h3 id="新しいタスクタイプを作成しましたが、生産に表示されません" tabindex="-1">新しいタスクタイプを作成しましたが、生産に表示されません <a class="header-anchor" href="#新しいタスクタイプを作成しましたが、生産に表示されません" aria-label="Permalink to “新しいタスクタイプを作成しましたが、生産に表示されません”">​</a></h3><p>新しいタスクタイプを作成した場合（<a href="./../configure-kitsu/#task-types">ドキュメントを参照</a>）、それが生産に表示されない場合は、<strong>Studio Library</strong>で作成されたタスクタイプを<strong>Production Library</strong>に明示的に追加する必要があります。</p><h4 id="違いを理解する" tabindex="-1">違いを理解する： <a class="header-anchor" href="#違いを理解する" aria-label="Permalink to “違いを理解する：”">​</a></h4><ul><li><strong>Studio Library</strong>：スタジオ全体で使用するすべてのタスクタイプが最初に作成され、保存される場所です。</li><li><strong>Production Library</strong>：各生産には独自のライブラリがあり、使用する前にタスクタイプをここに追加する必要があります。</li></ul><h4 id="生産にタスクタイプを追加する手順" tabindex="-1">生産にタスクタイプを追加する手順 <a class="header-anchor" href="#生産にタスクタイプを追加する手順" aria-label="Permalink to “生産にタスクタイプを追加する手順”">​</a></h4><ol><li><p>ナビゲーションメニューから生産の<strong>設定</strong>ページに移動します。<br><img src="'+n+'" alt="Production Settings page"></p></li><li><p><strong>タスクタイプ</strong>タブに移動します。<br><img src="'+p+'" alt="Task Type Settings page"></p></li><li><p>適切なエンティティタブ（例：アセット、ショット、シーケンス、エピソード、編集）を選択します。</p></li><li><p>右側のリストからタスクタイプを見つけてクリックして追加します。</p></li></ol><p>追加が完了したら、エンティティページに戻り、<strong>タスクタイプを追加</strong>をクリックします。<br><img src="'+g+'" alt="Add Task Type"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p><strong>権限</strong>:<br> メインメニューに<strong>設定</strong>オプションが表示されない場合、必要な権限を持っていない可能性があります。この場合は、スタジオ管理者に連絡してください。</p></div><hr><h3 id="タスクタイプの列が正しい順序になっていません" tabindex="-1">タスクタイプの列が正しい順序になっていません <a class="header-anchor" href="#タスクタイプの列が正しい順序になっていません" aria-label="Permalink to “タスクタイプの列が正しい順序になっていません”">​</a></h3><p>タスクタイプの列が順序通りでない場合は、以下の方法で調整できます：</p><ul><li><p><strong>スタジオ全体の順序</strong>:</p><ol><li>メインメニューの<strong>管理者</strong>セクションで<strong>タスクタイプ</strong>をクリックします。<br><img src="'+h+'" alt="Task Type admin Menu"></li><li>タスクタイプをドラッグ＆ドロップして希望の順序に並べ替えます。<br><img src="'+c+'" alt="Task Type order"></li></ol></li><li><p><strong>生産固有の順序</strong>:</p><ol><li>生産の<strong>設定</strong>ページに移動します。</li><li><strong>タスクタイプ</strong>タブに移動し、ドラッグ＆ドロップで順序を調整します。</li></ol></li></ul><hr><h3 id="タスクタイプの列が表示されていません" tabindex="-1">タスクタイプの列が表示されていません <a class="header-anchor" href="#タスクタイプの列が表示されていません" aria-label="Permalink to “タスクタイプの列が表示されていません”">​</a></h3><p>エンティティページでいくつかのタスクタイプの列が表示されない場合：</p><ol><li><p>部門フィルターを確認し、<strong>すべての部門</strong>に設定されていることを確認してください。<br><img src="'+d+'" alt="Department filtered view"></p></li><li><p><strong>追加情報を表示</strong>ボタンがハイライトされていることを確認してください。<br><img src="'+r+'" alt="Hide option"></p></li><li><p>列が縮小されている場合、追加情報が表示されないと列は表示されません。</p></li></ol><hr><h2 id="チームと割り当て" tabindex="-1">チームと割り当て <a class="header-anchor" href="#チームと割り当て" aria-label="Permalink to “チームと割り当て”">​</a></h2><h3 id="タスクに誰も割り当てることができません" tabindex="-1">タスクに誰も割り当てることができません <a class="header-anchor" href="#タスクに誰も割り当てることができません" aria-label="Permalink to “タスクに誰も割り当てることができません”">​</a></h3><p>コメントパネルの担当者リストが空の場合、<strong>People</strong>ページに追加した人が生産に追加されていないことを意味します。</p><h4 id="生産に人を追加する手順" tabindex="-1">生産に人を追加する手順 <a class="header-anchor" href="#生産に人を追加する手順" aria-label="Permalink to “生産に人を追加する手順”">​</a></h4><ol><li><p>生産メニューから<strong>チーム</strong>ページに移動します。<br><img src="'+m+'" alt="Team menu"></p></li><li><p><strong>チーム</strong>ページは空ですが、右側に人のリストが表示されます。<br><img src="'+b+'" alt="Team page empty"></p></li><li><p>個別または部門ごとに人を追加します。</p></li></ol><p>追加後、彼らは生産にアクセスできるようになり、タスクを割り当てることができます。</p><hr><h3 id="割り当てがすべて消えました" tabindex="-1">割り当てがすべて消えました <a class="header-anchor" href="#割り当てがすべて消えました" aria-label="Permalink to “割り当てがすべて消えました”">​</a></h3><p>担当者のアバターが表示されなくなった場合：</p><ol><li><p><strong>割り当てを非表示</strong>ボタンを誤ってクリックしていないか確認してください。<br><img src="'+r+'" alt="Hide option"></p></li><li><p>ボタンを再度クリックすると、アバターが再表示されます。</p></li></ol><hr><h2 id="生産管理" tabindex="-1">生産管理 <a class="header-anchor" href="#生産管理" aria-label="Permalink to “生産管理”">​</a></h2><h3 id="プロダクションをアーカイブまたは削除する方法" tabindex="-1">プロダクションをアーカイブまたは削除する方法 <a class="header-anchor" href="#プロダクションをアーカイブまたは削除する方法" aria-label="Permalink to “プロダクションをアーカイブまたは削除する方法”">​</a></h3><p>プロダクションへのアクセスが不要になった場合、アーカイブまたは削除を選択できます。</p><ul><li><strong>アーカイブ</strong>: プロダクションがナビゲーションメニューから削除されますが、参照用にデータは保持されます。</li><li><strong>削除</strong>: 永久的かつ不可逆的なアクションで、プロダクションをKitsuインスタンスから完全に削除します。</li></ul><h4 id="プロダクションをアーカイブする手順" tabindex="-1">プロダクションをアーカイブする手順 <a class="header-anchor" href="#プロダクションをアーカイブする手順" aria-label="Permalink to “プロダクションをアーカイブする手順”">​</a></h4><ol><li><p>メインメニューで<strong>STUDIO</strong>セクションの<strong>Productions</strong>を選択します。<br><img src="'+u+'" alt="Main Menu Productions"></p></li><li><p>アーカイブしたいプロダクションを見つけ、編集ボタンをクリックします。<br><img src="'+_+'" alt="Edit Productions"></p></li><li><p><strong>Status</strong>を<strong>Open</strong>から<strong>Closed</strong>に変更し、確定します。<br><img src="'+f+'" alt="Edit Productions option"></p></li></ol><p>これでプロダクションはアーカイブされ、ナビゲーションメニューには表示されなくなります。</p><hr><h4 id="プロダクションを削除する手順" tabindex="-1">プロダクションを削除する手順 <a class="header-anchor" href="#プロダクションを削除する手順" aria-label="Permalink to “プロダクションを削除する手順”">​</a></h4><p>アーカイブされたプロダクションのみ削除可能です。プロダクションを永久に削除する場合は、次の手順に従ってください:</p><ol><li><strong>Productions</strong>リストで、アーカイブ済み（Closed）のプロダクションにカーソルを合わせます。ゴミ箱アイコンが表示されます。</li><li>ゴミ箱アイコンをクリックすると、確認ダイアログが表示されます。</li><li>プロダクション名を入力して削除を確定します。</li></ol><p><img src="'+k+'" alt="Delete Production"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>プロダクションの削除は永久的で元に戻せません。本当に必要ない場合にのみこのアクションを実行してください。</p></div><hr><h2 id="その他" tabindex="-1">その他 <a class="header-anchor" href="#その他" aria-label="Permalink to “その他”">​</a></h2><h3 id="使用中のストレージを確認するには" tabindex="-1">使用中のストレージを確認するには？ <a class="header-anchor" href="#使用中のストレージを確認するには" aria-label="Permalink to “使用中のストレージを確認するには？”">​</a></h3><p>現在、Kitsuではインターフェイスやアカウントページでストレージ使用量を直接表示する機能はありません。そのため、アプリ内での生産やアセットの使用量を確認することはできません。</p><p>使用中のストレージを確認する必要がある場合：</p><ul><li>Kitsuがスタジオのサーバーでホストされている場合は、システム管理者またはITチームにお問い合わせください。</li><li>クラウドホスティングされたKitsuインスタンスを使用している場合は、<strong><a href="mailto:support@cg-wire.com" target="_blank" rel="noreferrer">support@cg-wire.com</a></strong> にスタジオ名とアカウント情報を記載してメールを送信してください。当社のチームが必要な情報を提供します。</li></ul>',58)])])}const w=i(P,[["render",x]]);export{v as __pageData,w as default};
